import { Component, EventEmitter, Input, OnChanges, Output, SimpleChanges, inject } from '@angular/core';
import { FormControl, FormGroup, FormsModule, ReactiveFormsModule, Validators } from '@angular/forms';
import { HttpClient } from '@angular/common/http';
import { lastValueFrom } from 'rxjs';
import { Address, RespostaCep } from '@trokai/shared-core';
import { AlertService } from '../../alert/alert.service';
import { MatButtonModule } from '@angular/material/button';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { NgxMaskDirective } from 'ngx-mask';

@Component({
  selector: 'tk-address-form',
  standalone: true,
  imports: [FormsModule, ReactiveFormsModule, MatFormFieldModule, MatInputModule, MatButtonModule, NgxMaskDirective],
  template: `
    <form [formGroup]="form" (ngSubmit)="save()" class="tk-address-form">
      <div class="tk-row">
        <mat-form-field appearance="outline" class="w-100">
          <mat-label>CEP</mat-label>
          <input matInput type="text" mask="00000-000" formControlName="zipCode" (keyup)="onChangeCEP()" />
          @if (viaCepError) { <mat-hint>CEP inválido</mat-hint> }
        </mat-form-field>
      </div>
      <div class="tk-row">
        <mat-form-field appearance="outline" class="w-100">
          <mat-label>Endereço</mat-label>
          <input matInput type="text" formControlName="street" />
        </mat-form-field>
      </div>
      <div class="tk-row tk-row--cols">
        <mat-form-field appearance="outline" class="tk-col-4">
          <mat-label>Número</mat-label>
          <input matInput type="text" formControlName="number" maxlength="6" />
        </mat-form-field>
        <mat-form-field appearance="outline" class="tk-col-8">
          <mat-label>Complemento</mat-label>
          <input matInput type="text" formControlName="complement" />
        </mat-form-field>
      </div>
      <div class="tk-row">
        <mat-form-field appearance="outline" class="w-100">
          <mat-label>Bairro</mat-label>
          <input matInput type="text" formControlName="neighborhood" />
        </mat-form-field>
      </div>
      <div class="tk-row tk-row--cols">
        <mat-form-field appearance="outline" class="tk-col-8">
          <mat-label>Cidade</mat-label>
          <input matInput readonly type="text" formControlName="city" />
        </mat-form-field>
        <mat-form-field appearance="outline" class="tk-col-4">
          <mat-label>Estado</mat-label>
          <input matInput readonly type="text" formControlName="state" />
        </mat-form-field>
      </div>
      @if (submit) {
        <div class="tk-row tk-actions">
          @if (encapsulated) {
            <button type="button" mat-button color="light" (click)="close()">Cancelar</button>
          }
          <button type="submit" mat-raised-button color="primary">Salvar</button>
        </div>
      }
    </form>
  `,
  styles: [`
    .tk-address-form { display: flex; flex-direction: column; gap: 0; }
    .tk-row { width: 100%; }
    .tk-row--cols { display: flex; gap: 12px; }
    .tk-col-4 { flex: 0 0 33.33%; }
    .tk-col-8 { flex: 1; }
    .tk-actions { display: flex; justify-content: flex-end; gap: 8px; margin-top: 16px; }
    .w-100 { width: 100%; }
  `],
})
export class TkAddressFormComponent implements OnChanges {
  @Input() encapsulated = false;
  @Input() address?: Address;
  @Input() submit = true;
  @Output() addressSave = new EventEmitter<Address>();
  @Output() formClose = new EventEmitter<void>();

  private http = inject(HttpClient);
  private alert = inject(AlertService);

  viaCepError = false;

  form = new FormGroup({
    street: new FormControl<string | null>(null, [Validators.required]),
    neighborhood: new FormControl<string | null>(null, [Validators.required]),
    city: new FormControl<string | null>(null, [Validators.required]),
    state: new FormControl<string | null>(null, [Validators.required]),
    zipCode: new FormControl<string | null>(null, [Validators.required, Validators.minLength(8), Validators.maxLength(8)]),
    number: new FormControl<string | null>(null, [Validators.required, Validators.maxLength(6)]),
    complement: new FormControl<string | null>(null),
  });

  onChangeCEP() {
    const zip = this.form.get('zipCode')?.value?.toString().replace('-', '');
    if (zip?.length === 8) this.requestCep(zip);
  }

  async requestCep(cep: string) {
    try {
      const res = await lastValueFrom(this.http.get<RespostaCep>(`https://viacep.com.br/ws/${cep}/json/`));
      this.form.patchValue({ street: res.logradouro, neighborhood: res.bairro, city: res.localidade, state: res.uf, number: null, complement: null });
      this.viaCepError = !!res.erro;
    // eslint-disable-next-line no-empty
    } catch {}
  }

  async save() {
    if (!this.form.valid) {
      this.alert.formError();
      return;
    }
    const v = this.form.value;
    const zipCode = +v.zipCode!.toString().replace('-', '');
    const address: Address = {
      zipCode,
      street: v.street!,
      number: v.number ? +v.number : undefined,
      complement: v.complement || undefined,
      neighborhood: v.neighborhood!,
      city: v.city!,
      state: v.state!,
      country: 'BRA',
    };
    if (!address.complement) delete address.complement;
    this.addressSave.emit(address);
  }

  validateForm() {
    Object.keys(this.form.controls).forEach((key) => {
      const c = this.form.get(key)!;
      c.markAsTouched();
      c.updateValueAndValidity();
    });
  }

  close() {
    this.formClose.emit();
  }

  ngOnChanges(changes: SimpleChanges) {
    if (changes['address'] && changes['address'].previousValue == null && changes['address'].currentValue != null && !this.form.valid) {
      const a = this.address!;
      this.form.patchValue({ ...a, zipCode: a.zipCode?.toString(), number: a.number?.toString() });
    }
  }
}

import { AfterViewInit, Component, ViewChild, inject } from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { Address, NavigationManager, equalAddresses } from '@trokai/shared-core';
import { BuyingService } from '@trokai/shared-data-access';
import { LoadingService } from '../../loading/loading.service';
import { UserService } from '@trokai/shared-data-access';
import { TkAddressFormComponent } from '../address-form/tk-address-form.component';

@Component({
  selector: 'tk-shipping-address',
  standalone: true,
  imports: [MatButtonModule, TkAddressFormComponent],
  template: `
    <h3 class="checkout-title">Endereço de entrega</h3>
    <div class="checkout-body">
      <tk-address-form [submit]="false" />
    </div>
    <div class="checkout-footer mt-40">
      <button mat-raised-button color="primary" (click)="onContinue()" [disabled]="!formRef?.form.valid">
        Continuar
      </button>
    </div>
  `,
})
export class TkShippingAddressComponent implements AfterViewInit {
  @ViewChild(TkAddressFormComponent) formRef!: TkAddressFormComponent;

  private navManager = inject(NavigationManager);
  private userService = inject(UserService);
  private buyingService = inject(BuyingService);
  private loading = inject(LoadingService);

  private currentAddress?: Address;

  ngAfterViewInit() {
    const user = this.navManager.currentUser();
    if (user?.address) {
      const a = user.address;
      this.formRef.form.patchValue({ ...a, zipCode: a.zipCode?.toString(), number: a.number?.toString() });
      this.currentAddress = user.address;
    }
  }

  async onContinue() {
    if (!this.formRef.form.valid) return;

    const v = this.formRef.form.value;
    const zipCode = +v.zipCode!.toString().replace('-', '');
    const address: Address = {
      zipCode,
      street: v.street!,
      number: v.number ? +v.number : undefined,
      complement: v.complement || undefined,
      neighborhood: v.neighborhood!,
      city: v.city!,
      state: v.state!,
      country: 'BRA',
    };
    if (!address.complement) delete address.complement;

    try {
      this.loading.start();
      if (!equalAddresses(address, this.currentAddress!)) {
        await this.userService.updateUser({ address });
        await this.navManager.syncUserData();
        await this.buyingService.afterAddressUpdate();
      }
      this.buyingService.navigateCheckout();
    } finally {
      this.loading.finish();
    }
  }
}

import { CurrencyPipe, NgClass, isPlatformServer } from '@angular/common';
import { Component, ElementRef, Input, OnInit, PLATFORM_ID, ViewChild, inject } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';
import { SearchLocationService } from '@trokai/shared-core';
import { BuyingService, ShippingInfo } from '@trokai/shared-data-access';
import { NgxMaskDirective, NgxMaskPipe } from 'ngx-mask';
import { CostPipe } from '../../pipes/cost.pipe';

@Component({
  selector: 'tk-zipcode-shipping-fee',
  standalone: true,
  imports: [MatFormFieldModule, NgClass, MatInputModule, FormsModule, MatProgressSpinnerModule, CurrencyPipe, CostPipe, NgxMaskDirective, NgxMaskPipe],
  template: `
    <div class="d-flex">
      @if (!typeZip && !zipLoading && zipCode) {
        <span class="d-block shipping-label label-body-2" role="button" tabindex="0" (click)="clickShippingLabel($event)" (keyup.enter)="clickShippingLabel($event)">
          Em até {{ shippingInfo?.maxDeliveryTime }} dias após o envio por
          <span>
            @if (shippingInfo?.fullShippingCost && shippingInfo!.fullShippingCost! > shippingInfo!.shippingCost) {
              <span class="label-body-2 color-gray-light-1 line-through">
                {{ shippingInfo!.fullShippingCost | cost | currency:'BRL':'symbol':'1.2' }}
              </span>
            }
            <b>{{ shippingInfo?.shippingCost ?? 0 | cost | currency:'BRL':'symbol':'1.0-2' }}</b>
          </span>
          (CEP {{ zipCode | mask:'00000-000' }})
        </span>
      }
      @if (!typeZip && !zipLoading && !zipCode) {
        <span class="d-block shipping-label label-body-2 color-primary" role="button" tabindex="0" (click)="clickShippingLabel($event)" (keyup.enter)="clickShippingLabel($event)">
          <b>Calcular frete de entrega</b>
        </span>
      }
      <mat-form-field appearance="outline" [ngClass]="{ 'd-none': !typeZip, 'd-block': typeZip }">
        <input matInput #zipInput [(ngModel)]="zipCode" (blur)="zipBlur()" (input)="zipChange()" type="text" mask="00000-000" placeholder="Digite o CEP" />
      </mat-form-field>
      @if (zipLoading) {
        <div class="d-flex align-items-center">
          <mat-spinner color="primary" class="spinner-nano"></mat-spinner>
          <span class="label-caption ms-4">Buscando valor do frete</span>
        </div>
      }
    </div>
  `,
})
export class TkZipcodeShippingFeeComponent implements OnInit {
  @Input() productId?: string;
  @ViewChild('zipInput') zipInput?: ElementRef;

  shippingInfo?: ShippingInfo;
  zipCode?: number;
  typeZip = false;
  zipLoading = false;

  private buyingService = inject(BuyingService);
  private locationService = inject(SearchLocationService);
  private platformId = inject<object>(PLATFORM_ID);

  ngOnInit() {
    if (isPlatformServer(this.platformId)) return;
    setTimeout(() => this.start());
  }

  start() {
    const location = this.locationService.getSearchLocationValue();
    if (location) {
      this.zipCode = location.zip;
      this.getShippingFee();
    }
  }

  async clickShippingLabel(event: Event) {
    event.stopPropagation();
    setTimeout(() => this.zipInput?.nativeElement.focus(), 200);
    this.typeZip = true;
  }

  async zipChange() {
    if (this.zipCode?.toString().length === 8) this.getShippingFee();
  }

  async getShippingFee() {
    this.zipLoading = true;
    this.typeZip = false;
    try {
      if (!this.productId || !this.zipCode) return;
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      this.shippingInfo = await this.buyingService.calculateShippingFee(this.zipCode.toString(), [{ _id: this.productId } as any]);
      this.locationService.changeSearchZip(this.zipCode!);
    } catch {
      this.zipCode = undefined;
      this.shippingInfo = undefined;
      this.typeZip = false;
    } finally {
      this.zipLoading = false;
    }
  }

  async zipBlur() {
    this.typeZip = false;
    if (this.zipCode?.toString().length !== 8) this.zipCode = undefined;
  }

}

import { Injectable, NgZone, inject } from '@angular/core';
import { MatDialog } from '@angular/material/dialog';
import { MatSnackBar } from '@angular/material/snack-bar';
import { Overlay } from '@angular/cdk/overlay';
import { DialogAlertComponent } from '../dialog-alert/dialog-alert.component';

@Injectable({
  providedIn: 'root',
})
export class AlertService {
  private dialog = inject(MatDialog);
  private snack = inject(MatSnackBar);
  private overlay = inject(Overlay);
  private ngZone = inject(NgZone);

  // --- snackbar toasts ---

  public alert(msg: string) {
    // eslint-disable-next-line no-empty
    try { this.show(msg); } catch {}
  }

  public errorDefault() {
    this.show('Ops! Algo deu errado!');
  }

  public success(msg: string) {
    this.show(msg);
  }

  public error(msg: string) {
    this.show(msg);
  }

  public warning(msg: string) {
    this.show(msg);
  }

  public postSuccess() {
    this.show('Informações salvas!');
  }

  public formError() {
    this.show('Preencha os campos corretamente');
  }

  private show(msg: string) {
    this.ngZone.runOutsideAngular(() => {
      const ref = this.snack.open(msg, '', { duration: 0 });
      // Zone.js-unpatched setTimeout so the dismiss timer never keeps
      // ApplicationRef unstable.
      const nativeSetTimeout: typeof setTimeout =
        (window as any).__zone_symbol__setTimeout ?? setTimeout;
      nativeSetTimeout(() => ref.dismiss(), 3000);
    });
  }

  // --- web question/info dialogs ---

  public async question(
    msg: string,
    title?: string,
    btnOkText?: string,
    btnNoText?: string,
    danger = false,
  ): Promise<boolean> {
    return this.openDialog({
      text: msg,
      title,
      btnOkText,
      btnNoText,
      danger,
      dialogQuestion: true,
    });
  }

  public async showDialog(title?: string, text?: string): Promise<boolean> {
    return this.openDialog(
      { title, text, btnText: 'OK' },
      this.overlay.scrollStrategies.noop(),
    );
  }

  // --- app-compat (Ionic modals redone as Material) ---

  public showAlert(header?: string, msg?: string): void {
    this.openDialog({ title: header, text: msg, btnText: 'Entendi' });
  }

  public showPromisedAlert(
    header?: string,
    msg?: string,
    okText = 'Entendi',
  ): Promise<boolean> {
    return this.openDialog({ title: header, text: msg, btnText: okText });
  }

  public askQuestion(
    header?: string,
    msg?: string,
    okText?: string,
    noText?: string,
    hideDanger = false,
  ): Promise<boolean> {
    return this.openDialog({
      title: header,
      text: msg,
      btnOkText: okText,
      btnNoText: noText,
      danger: !hideDanger,
      dialogQuestion: true,
    });
  }

  public showSuccess(
    title?: string,
    message?: string,
    okText = 'OK',
  ): Promise<boolean> {
    return this.openDialog({ title, text: message, btnText: okText });
  }

  private openDialog(data: any, scrollStrategy?: any): Promise<boolean> {
    return new Promise((resolve) => {
      this.ngZone.runOutsideAngular(() => {
        const dialogRef = this.dialog.open(DialogAlertComponent, {
          data,
          ...(scrollStrategy ? { scrollStrategy } : {}),
        });
        dialogRef.afterClosed().subscribe((result) => {
          this.ngZone.run(() => resolve(result?.response));
        });
      });
    });
  }
}

import {
  AfterViewInit,
  Component,
  EventEmitter,
  Output,
  ViewChild,
  inject,
} from '@angular/core';
import {
  FormControl,
  FormGroup,
  FormGroupDirective,
  FormsModule,
  ReactiveFormsModule,
  Validators,
} from '@angular/forms';
import { AsyncPipe, TitleCasePipe } from '@angular/common';
import { MatAutocompleteModule } from '@angular/material/autocomplete';
import { MatButtonModule } from '@angular/material/button';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatOptionModule } from '@angular/material/core';
import { NgxMaskPipe } from 'ngx-mask';
import { Observable, startWith, map } from 'rxjs';
import {
  BasicModel,
  getBanksList,
  User,
} from '@trokai/shared-core';
import {
  BankAccountHolderType,
  BankAccountModel,
  BankService,
} from '@trokai/shared-data-access';
import { NavigationManager } from '@trokai/shared-core';

@Component({
  selector: 'tk-bank-account-form',
  standalone: true,
  imports: [
    FormsModule,
    ReactiveFormsModule,
    MatFormFieldModule,
    MatInputModule,
    MatButtonModule,
    MatAutocompleteModule,
    MatOptionModule,
    NgxMaskPipe,
    AsyncPipe,
    TitleCasePipe,
  ],
  templateUrl: './tk-bank-account-form.component.html',
  styleUrl: './tk-bank-account-form.component.scss',
})
export class TkBankAccountFormComponent implements AfterViewInit {
  loaded = false;
  accountBkp!: BankAccountModel;
  changingAccount = false;

  form: FormGroup;
  banks = getBanksList();
  filteredBanks$: Observable<BasicModel<string>[]>;

  user!: User;

  @ViewChild(FormGroupDirective) formGroupDirective!: FormGroupDirective;
  @Output() saved = new EventEmitter<void>();

  private bankService = inject(BankService);
  private nav = inject(NavigationManager);

  constructor() {
    this.form = new FormGroup({
      holderName: new FormControl(null, Validators.required),
      bank: new FormControl(null, Validators.required),
      branchNumber: new FormControl(null, [Validators.required, Validators.minLength(4)]),
      branchCheckDigit: new FormControl(null, Validators.maxLength(1)),
      accountNumber: new FormControl(null, [Validators.required, Validators.minLength(4)]),
      accountCheckDigit: new FormControl(null, [Validators.required, Validators.minLength(1), Validators.maxLength(1)]),
    });

    this.filteredBanks$ = this.form.get('bank')!.valueChanges.pipe(
      startWith(''),
      map((v) => {
        if (v && typeof v !== 'string') return [];
        return this._filterBanks(v ?? '');
      }),
    );
  }

  displayBank(option: BasicModel<string>): string {
    return option?.value ?? '';
  }

  private _filterBanks(value: string): BasicModel<string>[] {
    const lower = value.toLowerCase();
    if (!lower) return this.banks.slice(0, 30);
    return this.banks
      .filter((b) => b.value.toLowerCase().includes(lower))
      .slice(0, 30);
  }

  ngAfterViewInit() { this.load(); }

  async load() {
    this.loaded = false;
    this.user = this.nav.currentUser()!;
    const account = await this.bankService.fetchAccount();

    if (account) {
      const banco = this.banks.find((b) => b._id === account.bank || b._id === account.bank?.toString().padStart(3, '0'));
      this.form.patchValue({ ...account, bank: banco });
      this.form.disable();
      this.accountBkp = account;
    }
    this.loaded = true;
  }

  selectBank(banco: BasicModel<string>) {
    this.form.get('bank')!.setValue(banco);
  }

  changeAccount() {
    this.formGroupDirective.resetForm();
    this.form.reset();
    this.form.enable();
    this.changingAccount = true;
  }

  cancelChange() {
    this.changingAccount = false;
    this.load();
  }

  async save() {
    if (this.form.invalid || !this.form.get('bank')?.value?._id) return;

    const fv = this.form.getRawValue();
    const account = new BankAccountModel();

    account.holderName = fv.holderName;
    account.bank = fv.bank._id.toString().padStart(3, '0');
    account.branchNumber = fv.branchNumber;
    account.branchCheckDigit = fv.branchCheckDigit;
    account.accountNumber = fv.accountNumber;
    account.accountCheckDigit = fv.accountCheckDigit;
    account.holderDocument = this.user?.cpf ?? '';
    account.holderType = account.holderDocument.length === 11
      ? BankAccountHolderType.INDIVIDUAL
      : BankAccountHolderType.COMPANY;

    if (
      !this.accountBkp ||
      account.holderName !== this.accountBkp.holderName ||
      account.holderDocument !== this.accountBkp.holderDocument ||
      (+account.bank! !== +(this.accountBkp.bank ?? '')) ||
      account.branchNumber !== this.accountBkp.branchNumber ||
      account.branchCheckDigit !== this.accountBkp.branchCheckDigit ||
      account.accountNumber !== this.accountBkp.accountNumber ||
      account.accountCheckDigit !== this.accountBkp.accountCheckDigit
    ) {
      await this.bankService.saveAccount(account);
    }

    this.saved.emit();
  }
}

import { Component, ElementRef, OnInit, ViewChild, inject } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { MatButtonModule } from '@angular/material/button';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';
import { BuyingService, CheckoutLocal } from '@trokai/shared-data-access';
import { LoadingService } from '../../loading/loading.service';

@Component({
  selector: 'tk-coupon-form',
  standalone: true,
  imports: [FormsModule, MatFormFieldModule, MatInputModule, MatButtonModule, MatIconModule],
  templateUrl: './tk-coupon-form.component.html',
  styleUrl: './tk-coupon-form.component.scss',
})
export class TkCouponFormComponent implements OnInit {
  couponCode!: string;
  checkoutLocal!: CheckoutLocal;
  couponApplied = false;
  showInput = false;

  @ViewChild('couponInput') couponInput!: ElementRef;

  private loading = inject(LoadingService);
  private buyingService = inject(BuyingService);

  ngOnInit() {
    this.buyingService.checkoutLocal$.subscribe((c) => (this.checkoutLocal = c!));
  }

  async onApply() {
    if (!this.couponCode) return;
    try {
      this.loading.start();
      this.checkoutLocal.couponCode = this.couponCode;
      this.buyingService.setCheckoutLocal(this.checkoutLocal);
      await this.buyingService.getCheckoutData();
      this.couponApplied = true;
    } catch {
      this.checkoutLocal.couponCode = undefined as any;
      this.couponApplied = false;
    } finally {
      this.loading.finish();
    }
  }

  onBlur() {
    if (!this.couponCode) this.showInput = false;
  }

  onShowInput() {
    this.showInput = true;
    setTimeout(() => this.couponInput?.nativeElement.focus(), 200);
  }

  async clearSelection() {
    try {
      this.loading.start();
      this.buyingService.setCheckoutLocal({ ...this.checkoutLocal, couponCode: undefined as any });
      await this.buyingService.getCheckoutData();
      this.couponApplied = false;
      this.showInput = false;
      this.couponCode = undefined as any;
    } finally {
      this.loading.finish();
    }
  }
}

import { Component, inject } from '@angular/core';
import {
  MAT_DIALOG_DATA,
  MatDialogRef,
  MatDialogModule,
} from '@angular/material/dialog';
import { MatButtonModule } from '@angular/material/button';

export interface DialogAlertData {
  success?: boolean;
  error?: boolean;
  warning?: boolean;
  title?: string;
  text?: string;
  btnText?: string;
  btnOkText?: string;
  btnNoText?: string;
  dialogQuestion?: boolean;
  danger?: boolean;
}

@Component({
  selector: 'tk-dialog-alert',
  templateUrl: './dialog-alert.component.html',
  styleUrls: ['./dialog-alert.component.scss'],
  standalone: true,
  imports: [MatDialogModule, MatButtonModule],
})
export class DialogAlertComponent {
  public dialogRef = inject(MatDialogRef<DialogAlertComponent>);
  public data = inject<DialogAlertData>(MAT_DIALOG_DATA);

  close(action: any): void {
    this.dialogRef.close({ response: action });
  }
}

import { BasicModel } from '@trokai/shared-core';
import { TitleCasePipe, AsyncPipe } from '@angular/common';
import { Component, Input, OnInit, EventEmitter, Output } from '@angular/core';
import {
  FormControl,
  FormGroup,
  FormsModule,
  ReactiveFormsModule,
} from '@angular/forms';
import { ErrorStateMatcher, MatOptionModule } from '@angular/material/core';
import { Observable } from 'rxjs';
import { startWith, map } from 'rxjs/operators';
import { MatTooltipModule } from '@angular/material/tooltip';
import { MatIconModule } from '@angular/material/icon';
import { MatAutocompleteModule } from '@angular/material/autocomplete';
import { MatInputModule } from '@angular/material/input';
import { MatFormFieldModule } from '@angular/material/form-field';

@Component({
  selector: 'tk-autocomplete',
  standalone: true,
  imports: [
    FormsModule,
    ReactiveFormsModule,
    MatFormFieldModule,
    MatInputModule,
    MatAutocompleteModule,
    MatIconModule,
    MatTooltipModule,
    MatOptionModule,
    AsyncPipe,
    TitleCasePipe,
  ],
  templateUrl: './tk-autocomplete.component.html',
  styleUrl: './tk-autocomplete.component.scss',
})
export class TkAutocompleteComponent<T extends BasicModel<string | number>>
  implements OnInit
{
  @Input() options!: T[];
  @Input() minLength = 0;
  @Input() name!: string;
  @Input() parentForm!: FormGroup;
  @Input() controlName!: string;
  @Input() allowCustom = false;

  filteredOptions!: Observable<T[]>;

  notOnList = false;

  @Output() selected = new EventEmitter();

  readonly errorStateMatcher: ErrorStateMatcher = {
    isErrorState: (ctrl: FormControl) =>
      ctrl && ctrl.dirty && this.notOnList && !this.allowCustom,
  };

  ngOnInit() {
    this.filteredOptions = this.parentForm
      .get(this.controlName)!
      .valueChanges.pipe(
        startWith(''),
        map((value) => {
          // check if selected already
          if (value && typeof value !== 'string') return [];

          const len = value ? value.length : 0;

          // open by default
          if (this.minLength == 0) return this._filter(value ?? '');
          if (len < this.minLength) return [];

          return this._filter(value ?? '');
        })
      );
  }

  displayFn(option: T): string {
    const tcp = new TitleCasePipe();
    return tcp.transform(option?.value);
  }

  private _filter(value: string): T[] {
    const normalizedFilter = value.toLowerCase();

    return this.options
      .map((option) => {
        const optionValue = option.value.toString().toLowerCase();
        let score = 0;

        if (optionValue === normalizedFilter) {
          score = 3; // exact match
        } else if (optionValue.startsWith(normalizedFilter)) {
          score = 2; // starts with
        } else if (optionValue.includes(normalizedFilter)) {
          score = 1; // contains
        }

        return { option, score };
      })
      .filter((item) => item.score > 0)
      .sort((a, b) => b.score - a.score)
      .map((item) => item.option);
  }

  change() {
    const val: any = this.parentForm.get(this.controlName)!.value;
    this.notOnList = val?._id == null || val?.value == null;

    if ((!this.notOnList && !this.allowCustom) || val == null)
      this.selected.emit(val);
  }

  clear() {
    this.parentForm.get(this.controlName)!.setValue(null);
    this.change();
  }

  verify() {
    // user typed something after selecting
    const ctrl: any = this.parentForm.get(this.controlName)!.value;

    if (!ctrl || !ctrl.value) {
      this.change();
      return;
    }

    if (
      !this.allowCustom &&
      !this.options.find(
        (item) => item.value.toLowerCase() === ctrl.value.toLowerCase()
      )
    ) {
      this.parentForm.get(this.controlName)!.setValue(null);
      this.change();
    }
  }

  showClear() {
    return (
      this.parentForm.get(this.controlName)!.value &&
      !this.parentForm.get(this.controlName)!.disabled
    );
  }
}

import { Pipe, PipeTransform, inject } from '@angular/core';
import { CatalogService } from '@trokai/shared-data-access';

/**
 * Template facility for items-map name lookups — no per-component map plumbing.
 *   {{ clothes.gender | itemName: 'gender' }}
 *   {{ clothes.special | itemName: 'special' }}
 *   {{ clothes.category | itemName: 'category' }}
 *   {{ clothes.condition | itemName: 'condition' }}
 *   {{ clothes.age | itemName: 'age' }}
 *   {{ clothes.piece | itemName: 'piece' : clothes.category }}
 *   {{ clothes.size | itemName: 'size' : clothes.category : clothes.age }}
 *
 * Impure so the value resolves once the catalog (/init) has loaded.
 */
@Pipe({ name: 'itemName', standalone: true, pure: false })
export class ItemNamePipe implements PipeTransform {
  private catalog = inject(CatalogService);

  transform(
    id: number,
    kind: 'gender' | 'special' | 'condition' | 'age' | 'category' | 'piece' | 'size',
    category?: number,
    age?: number,
  ): string {
    if (id == null) return '';

    switch (kind) {
      case 'gender':
        return this.catalog.getGenderName(id) ?? '';
      case 'special':
        return this.catalog.getSpecialName(id) ?? '';
      case 'condition':
        return this.catalog.getConditionName(id) ?? '';
      case 'age':
        return this.catalog.getAgeName(id) ?? '';
      case 'category':
        return this.catalog.getCategoryName(id) ?? '';
      case 'piece':
        return this.catalog.getPieceName(id, category!) ?? '';
      case 'size':
        return this.catalog.getSizeName(id, category!, age!) ?? '';
      default:
        return '';
    }
  }
}

