export interface ProfileFormValue {
  name: string;
  email: string;
  cpf: string; // digits only
  phone: string; // digits only
  birthday: Date;
}

const NAME_PATTERN = /^[A-Za-záàâãéèêíóôõúçÁÀÂÃÉÈÍÓÔÕÚÇ \d]+$/;

@Component({
  selector: 'tk-profile-form',
  templateUrl: './profile-form.component.html',
  styleUrls: ['./profile-form.component.scss'],
  standalone: true,
  imports: [
    ReactiveFormsModule,
    MatFormFieldModule,
    MatInputModule,
    MatIconModule,
    MatButtonModule,
    MatTooltipModule,
    NgxMaskDirective,
  ],
})
export class ProfileFormComponent implements OnChanges {
  @Input() user!: User;
  @Input() loading = false;
  @Input() completingInformation = false;
  @Input() emailRegistered = false;
  @Input() phoneRegistered = false;

  @Output() submitted = new EventEmitter<ProfileFormValue>();
  @Output() emailBlur = new EventEmitter<string>();
  @Output() phoneBlur = new EventEmitter<string>();
  @Output() verifyPhone = new EventEmitter<void>();

  shortName = false;
  nameValid = true;
  under18 = false;
  invalidBirth = false;
  showedDocMsg = false;

  readonly form = new FormGroup({
    name: new FormControl<string | null>(null, [
      Validators.required,
      Validators.minLength(3),
    ]),
    email: new FormControl<string | null>(null, [
      Validators.required,
      Validators.email,
    ]),
    cpf: new FormControl<string | null>(null, [Validators.required]),
    birthday: new FormControl<string | null>(null, [Validators.required]),
    phone: new FormControl<string | null>(null, [Validators.required]),
  });

  readonly nameErrorMatcher: ErrorStateMatcher = {
    isErrorState: (ctrl: FormControl) =>
      (ctrl && ctrl.invalid && ctrl.dirty) || this.shortName || !this.nameValid,
  };
  readonly emailErrorMatcher: ErrorStateMatcher = {
    isErrorState: (ctrl: FormControl) =>
      (ctrl && ctrl.invalid && ctrl.dirty) || this.emailRegistered,
  };
  readonly phoneErrorMatcher: ErrorStateMatcher = {
    isErrorState: (ctrl: FormControl) =>
      (ctrl && ctrl.invalid && ctrl.dirty) || this.phoneRegistered,
  };
  readonly birthErrorMatcher: ErrorStateMatcher = {
    isErrorState: (ctrl: FormControl) =>
      (ctrl && ctrl.invalid && ctrl.dirty) || this.under18 || this.invalidBirth,
  };

  private alertService = inject(AlertService);

  ngOnChanges(changes: SimpleChanges) {
    if (changes['user'] && this.user) this.fillForm();
  }

  fillForm() {
    if (this.form.valid) return;
    this.form.patchValue({
      name: this.user.name,
      email: this.user.email,
      cpf: this.user.cpf,
      phone: this.user.phone,
    });

    if (this.user.cpf) this.form.get('cpf')!.disable();

    if (this.user.birthday) {
      this.form
        .get('birthday')!
        .setValue(dayjs(this.user.birthday).format('DD/MM/YYYY'));
      this.form.get('birthday')!.disable();
    }

    this.changeName();
  }

  changeName() {
    const value = this.form.get('name')!.value ?? '';
    this.shortName = !!value && value.trim().split(' ').length === 1;
    this.nameValid = NAME_PATTERN.test(value);
  }

  changeBirthday() {
    const formDate = this.form.get('birthday');
    if (!formDate || formDate.disabled) return;

    const mDate = dayjs(this.parseDateString(formDate.value!));
    if (formDate.value && formDate.valid && mDate.isValid()) {
      this.invalidBirth = false;
      this.under18 = dayjs(new Date()).diff(mDate, 'year') < 18;
    } else {
      this.under18 = false;
      this.invalidBirth = true;
    }
  }

  focusCPF() {
    if (this.showedDocMsg) return;
    this.alertService.showDialog(
      'Atenção ao CPF',
      'Se você fizer uma venda pelo Trokaí, a conta bancária utilizada para receber o pagamento deverá estar vinculada a esse mesmo CPF. Caso o documento cadastrado pertença a um menor de 18 anos, a conta não poderá publicar anúncios.',
    );
    this.showedDocMsg = true;
  }

  onEmailBlur() {
    if (this.form.get('email')!.valid)
      this.emailBlur.emit(this.form.get('email')!.value ?? undefined);
  }

  onPhoneBlur() {
    if (this.form.get('phone')!.valid)
      this.phoneBlur.emit(this.form.get('phone')!.value ?? undefined);
  }

  get phoneMatches(): boolean {
    return (
      this.form.get('phone')!.valid &&
      this.form.get('phone')!.value === this.user?.phone &&
      !this.phoneRegistered
    );
  }

  parseDateString(input: string) {
    const [day, month, year] = input.split('/');
    return `${month}/${day}/${year}`;
  }

  submit() {
    if (this.loading) return;
    this.changeBirthday();

    if (this.under18 || this.shortName || !this.nameValid) return;

    if (this.form.invalid) {
      this.alertService.alert('Preencha todos os campos corretamente');
      return;
    }

    this.submitted.emit({
      name: this.form.get('name')!.value!,
      email: this.form.get('email')!.value!,
      cpf: this.digits(this.form.get('cpf')!.value!),
      phone: this.digits(this.form.get('phone')!.value!),
      birthday: new Date(
        this.parseDateString(this.form.get('birthday')!.value!),
      ),
    });
  }

  private digits(value: string): string {
    return value ? (value.match(/\d/g) ?? []).join('') : value;
  }
}

import {
  Component,
  EventEmitter,
  Input,
  OnInit,
  Output,
  inject,
} from '@angular/core';
import {
  FormControl,
  FormGroup,
  Validators,
  ReactiveFormsModule,
} from '@angular/forms';
import { ErrorStateMatcher } from '@angular/material/core';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatCheckboxModule } from '@angular/material/checkbox';
import { MatRadioModule } from '@angular/material/radio';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { TextFieldModule } from '@angular/cdk/text-field';
import { Clipboard } from '@angular/cdk/clipboard';
import {
  SellerProfileStatus,
  StoreVisibility,
  User,
} from '@trokai/shared-core';
import { TkUserAvatarComponent } from '../user-avatar/user-avatar.component';
import { AlertService } from '../../alert/alert.service';

export interface SellerProfileValue {
  storeName: string;
  nickname: string;
  inPerson: boolean;
  shipping: boolean;
  profileBio: string;
  storeVisibility: StoreVisibility;
}

@Component({
  selector: 'tk-seller-profile',
  templateUrl: './seller-profile.component.html',
  styleUrls: ['./seller-profile.component.scss'],
  standalone: true,
  imports: [
    ReactiveFormsModule,
    MatFormFieldModule,
    MatInputModule,
    MatCheckboxModule,
    MatRadioModule,
    MatButtonModule,
    MatIconModule,
    TextFieldModule,
    TkUserAvatarComponent,
  ],
})
export class SellerProfileComponent implements OnInit {
  @Input() user!: User;
  @Input() previewAvatarUrl: string | null = null;
  @Input() pictureUpdating = false;
  /** Whether the seller will have an avatar after save (deferred-upload aware). */
  @Input() avatarPresent = true;
  @Input() requireAvatar = true;
  @Input() showBio = true;
  @Input() showStoreVisibility = false;
  /** Seller-review records used to label requested adjustments (web). */
  @Input() sellerReviews: { _id: number; info: string }[] = [];

  @Output() submitted = new EventEmitter<SellerProfileValue>();

  readonly SellerProfileStatus = SellerProfileStatus;
  readonly StoreVisibility = StoreVisibility;
  readonly nicknamePattern = /^[a-zA-Z0-9._-]+(?<!\.)$/;

  submitAttempted = false;
  initialNickname: string | null = null;
  nicknameEdited = false;

  readonly form = new FormGroup({
    storeName: new FormControl<string | null>(null, [
      Validators.required,
      Validators.minLength(3),
      Validators.maxLength(50),
    ]),
    nickname: new FormControl<string | null>(null, [
      Validators.required,
      Validators.pattern(this.nicknamePattern),
      Validators.minLength(3),
      Validators.maxLength(25),
    ]),
    inPerson: new FormControl<boolean | null>(null),
    shipping: new FormControl<boolean | null>(null),
    profileBio: new FormControl<string | null>(null, Validators.maxLength(160)),
    storeVisibility: new FormControl<StoreVisibility | null>(null),
  });

  readonly nicknameErrorMatcher: ErrorStateMatcher = {
    isErrorState: (ctrl: FormControl) =>
      ctrl && ctrl.dirty && this.invalidNickname(),
  };

  private alert = inject(AlertService);
  private clipboard = inject(Clipboard);

  ngOnInit() {
    if (this.user) {
      this.form.patchValue(this.user as Partial<SellerProfileValue> & object);
      this.initialNickname = this.user.nickname;
      if (this.user.nickname) this.nicknameEdited = true;
      if (this.showStoreVisibility && this.user.storeVisibility == null) {
        this.form.get('storeVisibility')!.setValue(StoreVisibility.OPEN);
      }
    }

    this.form.get('storeName')!.valueChanges.subscribe((value: string | null) => {
      if (!this.nicknameEdited) {
        this.form
          .get('nickname')!
          .setValue(this.toSlug(value ?? ''), { emitEvent: false });
      }
    });
  }

  get avatarSatisfied(): boolean {
    return !this.requireAvatar || this.avatarPresent;
  }

  getAdjustLabel(id: number): string {
    return this.sellerReviews.find((r) => r._id === id)?.info ?? '';
  }

  formValid(): boolean {
    if (!this.avatarSatisfied) return false;

    if (!this.form.valid) {
      this.alert.formError();
      return false;
    }

    if (!this.form.get('shipping')!.value && !this.form.get('inPerson')!.value) {
      return false;
    }

    if (this.showStoreVisibility && !this.form.get('storeVisibility')!.value) {
      return false;
    }

    return true;
  }

  async save() {
    this.submitAttempted = true;
    if (!this.formValid()) return;

    const nickname = this.form.get('nickname')!.value?.toLowerCase() ?? '';

    if (this.initialNickname && nickname != this.initialNickname) {
      const ok = await this.alert.question(
        'Ao mudar seu nickname, os links antigos para seu armário deixam de funcionar. Deseja continuar?',
        'Alteração de nickname',
        'Confirmar alteração',
        'Cancelar',
      );
      if (!ok) {
        this.form.get('nickname')!.setValue(this.initialNickname);
        return;
      }
    }

    this.submitted.emit({
      storeName: this.form.get('storeName')!.value!,
      nickname,
      inPerson: this.form.get('inPerson')!.value!,
      shipping: this.form.get('shipping')!.value!,
      profileBio: this.form.get('profileBio')!.value!,
      storeVisibility: this.form.get('storeVisibility')!.value!,
    });
  }

  invalidNickname(): boolean {
    return !!this.form.get('nickname')!.errors?.['pattern'];
  }

  changeNickname() {
    this.nicknameEdited = true;
    const word = this.form.get('nickname')!.value ?? '';
    const newWord = word
      .toLowerCase()
      .replace(/ +/g, '-')
      .replace(/[^a-z0-9._-]/g, '')
      .replace(/-+/g, '-');

    if (newWord !== word) this.form.get('nickname')!.setValue(newWord);
  }

  trimNickname() {
    const value: string = this.form.get('nickname')!.value ?? '';
    this.form.get('nickname')!.setValue(value.replace(/[-_.]+$/, ''));
  }

  copyLink() {
    this.clipboard.copy(`https://trokai.com.br/${this.user.nickname}`);
    this.alert.success('Link da loja copiado!');
  }

  toSlug(value: string): string {
    if (!value) return '';
    return value
      .toLowerCase()
      .normalize('NFD')
      .replace(/[̀-ͯ]/g, '')
      .replace(/[^a-z0-9.-]/g, '-')
      .replace(/-+/g, '-')
      .substring(0, 25)
      .replace(/\.$/, '');
  }
}
